    "startFrame": 26445,
    "durationSec": 2.997333333333333,
    "durationFrames": 90,
    "speaker": "ずんだもん",
    "text": "ポイント3。そして何より重要なのだ。",
    "speakerColor": "#22c55e",
    "sceneId": 24,
    "sceneTitle": "自由意志は二択ではなくグラデーション"
